import React, { useState, useEffect } from "react";
import logo from "../assets/logo.png";

// Después reemplazaremos estos fondos por imágenes reales
const slides = [
  {
    image:
      "https://images.unsplash.com/photo-1588776814546-1ffcf47267a8?w=1600",
    title: "Smile Together",
    subtitle: "La salud bucal a través de la sonrisa",
  },

  {
    image:
      "https://images.unsplash.com/photo-1609840114035-3c981b782dfe?w=1600",
    title: "Prevención y educación",
    subtitle: "Una sonrisa sana comienza con buenos hábitos",
  },

  {
    image:
      "https://images.unsplash.com/photo-1629909613654-28e377c37b09?w=1600",
    title: "La salud es un derecho",
    subtitle: "La dignidad también se refleja en una sonrisa",
  },
];

export default function Carousel() {
  const [current, setCurrent] = useState(0);

  useEffect(() => {
    const interval = setInterval(() => {
      setCurrent((prev) => (prev + 1) % slides.length);
    }, 5000);

    return () => clearInterval(interval);
  }, []);

  return (
    <div
      style={{
        ...styles.container,
        backgroundImage: `url(${slides[current].image})`,
      }}
    >
      <div style={styles.overlay}>
        <img src={logo} alt="logo" style={styles.logo} />

        <h1 style={styles.title}>{slides[current].title}</h1>

        <p style={styles.subtitle}>{slides[current].subtitle}</p>
      </div>
    </div>
  );
}

const styles = {
  container: {
    height: "500px",
    backgroundSize: "cover",
    backgroundPosition: "center",
    display: "flex",
    alignItems: "center",
    justifyContent: "center",
  },

  overlay: {
    width: "100%",
    height: "100%",
    backgroundColor: "rgba(0,0,0,.35)",
    display: "flex",
    flexDirection: "column",
    alignItems: "center",
    justifyContent: "center",
    color: "white",
    textAlign: "center",
    padding: "2rem",
  },

  logo: {
    width: "120px",
    marginBottom: "1rem",
  },

  title: {
    fontSize: "3rem",
    fontWeight: "700",
    marginBottom: "1rem",
  },

  subtitle: {
    fontSize: "1.2rem",
    maxWidth: "700px",
  },
};
